@strawberry.type
class Seller:
    id: int
    name: str
    email: str
    rating: float
    description: Optional[str]

    @strawberry.field
    def products(self, info: Info) -> List["Product"]:
        db: Session = info.context["db"]
        seller_model = db.query(SellerModel).options(
            joinedload(SellerModel.products)
            .joinedload(ProductModel.reviews),
            joinedload(SellerModel.products)
            .joinedload(ProductModel.images),
            joinedload(SellerModel.products)
            .joinedload(ProductModel.categories),
            joinedload(SellerModel.products)
            .joinedload(ProductModel.seller),
        ).filter(SellerModel.id == self.id).first()
        if not seller_model:
            return []
        return [convert_product(p) for p in seller_model.products]


@strawberry.type
class Category:
    id: int
    name: str
