    @strawberry.field
    def parent(self, info: Info) -> Optional["Category"]:
        if self.parent_id is None:
            return None
        db: Session = info.context["db"]
        parent_model = db.query(CategoryModel).filter(CategoryModel.id == self.parent_id).first()
