    @strawberry.field
    def children(self, info: Info) -> List["Category"]:
        db: Session = info.context["db"]
        children_models = db.query(CategoryModel).filter(CategoryModel.parent_id == self.id).all()
        return [convert_category(c) for c in children_models]

    @strawberry.field
    def products(self, info: Info) -> List["Product"]:
        db: Session = info.context["db"]
