@strawberry.type
class Product:
    id: int
    name: str
    description: Optional[str]
    price: float
    stock: int
    seller_id: int
    _reviews: strawberry.Private[List[ReviewModel]]
    _images: strawberry.Private[List[ImageModel]]
    _categories: strawberry.Private[List[CategoryModel]]
    _seller: strawberry.Private[Optional[SellerModel]]

    @strawberry.field
    def reviews(self) -> List[Review]:
        return [convert_review(r) for r in self._reviews]

    @strawberry.field
    def images(self) -> List[Image]:
        return [convert_image(i) for i in self._images]

    @strawberry.field
    def categories(self) -> List[Category]:
        return [convert_category(c) for c in self._categories]

    @strawberry.field
    def seller(self) -> Optional[Seller]:
        if self._seller is None:
            return None
        return convert_seller(self._seller)

    @strawberry.field
    def average_rating(self) -> Optional[float]:
        if not self._reviews:
            return None
        return sum(r.rating for r in self._reviews) / len(self._reviews)

    @strawberry.field
    def review_count(self) -> int:
        return len(self._reviews)

    @strawberry.field
    def primary_image(self) -> Optional[Image]:
        for img in self._images:
            if img.is_primary:
                return convert_image(img)
        if self._images:
            return convert_image(self._images[0])
        return None


# Converter functions
def convert_review(model: ReviewModel) -> Review:
    return Review(
        id=model.id,
        product_id=model.product_id,
        reviewer_name=model.reviewer_name,
        rating=model.rating,
        title=model.title,
        comment=model.comment,
    )


def convert_image(model: ImageModel) -> Image:
    return Image(
        id=model.id,
        product_id=model.product_id,
        url=model.url,
        alt_text=model.alt_text,
        is_primary=bool(model.is_primary),
    )


def convert_seller(model: SellerModel) -> Seller:
    return Seller(
        id=model.id,
        name=model.name,
        email=model.email,
        rating=model.rating,
        description=model.description,
    )


def convert_category(model: CategoryModel) -> Category:
    return Category(
        id=model.id,
        name=model.name,
        description=model.description,
        parent_id=model.parent_id,
    )


def convert_product(model: ProductModel) -> Product:
    return Product(
        id=model.id,
        name=model.name,
        description=model.description,
        price=model.price,
        stock=model.stock,
        seller_id=model.seller_id,
        _reviews=model.reviews if model.reviews else [],
        _images=model.images if model.images else [],
        _categories=model.categories if model.categories else [],
        _seller=model.seller,
    )


