@strawberry.input
class ProductFilterInput:
    min_price: Optional[float] = None
    max_price: Optional[float] = None
    seller_id: Optional[int] = None
    category_id: Optional[int] = None
    in_stock: Optional[bool] = None
    search: Optional[str] = None


def get_products_query(db: Session):
    return db.query(ProductModel).options(
        joinedload(ProductModel.reviews),
        joinedload(ProductModel.images),
        joinedload(ProductModel.categories),
        joinedload(ProductModel.seller),
    )


# Query type
@strawberry.type
class Query:
    @strawberry.field
    def products(
        self,
        info: Info,
        filter: Optional[ProductFilterInput] = None,
        limit: Optional[int] = None,
        offset: Optional[int] = None,
    ) -> List[Product]:
        db: Session = info.context["db"]
        query = get_products_query(db)

        if filter:
            if filter.min_price is not None:
                query = query.filter(ProductModel.price >= filter.min_price)
            if filter.max_price is not None:
                query = query.filter(ProductModel.price <= filter.max_price)
            if filter.seller_id is not None:
                query = query.filter(ProductModel.seller_id == filter.seller_id)
            if filter.in_stock is not None:
                if filter.in_stock:
                    query = query.filter(ProductModel.stock > 0)
                else:
                    query = query.filter(ProductModel.stock == 0)
            if filter.search is not None:
                search_term = f"%{filter.search}%"
                query = query.filter(
                    ProductModel.name.ilike(search_term)
                    | ProductModel.description.ilike(search_term)
                )
            if filter.category_id is not None:
                query = query.filter(
                    ProductModel.categories.any(CategoryModel.id == filter.category_id)
                )

        if offset is not None:
            query = query.offset(offset)
        if limit is not None:
            query = query.limit(limit)

        products = query.all()
        return [convert_product(p) for p in products]

    @strawberry.field
    def product(self, info: Info, id: int) -> Optional[Product]:
        db: Session = info.context["db"]
        product = get_products_query(db).filter(ProductModel.id == id).first()
        if not product:
            return None
        return convert_product(product)

    @strawberry.field
    def sellers(self, info: Info) -> List[Seller]:
        db: Session = info.context["db"]
        sellers = db.query(SellerModel).all()
        return [convert_seller(s) for s in sellers]

    @strawberry.field
    def seller(self, info: Info, id: int) -> Optional[Seller]:
        db: Session = info.context["db"]
        seller = db.query(SellerModel).filter(SellerModel.id == id).first()
        if not seller:
            return None
        return convert_seller(seller)

    @strawberry.field
    def categories(self, info: Info, root_only: bool = False) -> List[Category]:
        db: Session = info.context["db"]
        query = db.query(CategoryModel)
        if root_only:
            query = query.filter(CategoryModel.parent_id.is_(None))
        categories = query.all()
        return [convert_category(c) for c in categories]

    @strawberry.field
    def category(self, info: Info, id: int) -> Optional[Category]:
        db: Session = info.context["db"]
        category = db.query(CategoryModel).filter(CategoryModel.id == id).first()
        if not category:
            return None
        return convert_category(category)

    @strawberry.field
    def reviews(
        self,
        info: Info,
        product_id: Optional[int] = None,
        min_rating: Optional[int] = None,
    ) -> List[Review]:
        db: Session = info.context["db"]
        query = db.query(ReviewModel)
        if product_id is not None:
            query = query.filter(ReviewModel.product_id == product_id)
        if min_rating is not None:
            query = query.filter(ReviewModel.rating >= min_rating)
        reviews = query.all()
        return [convert_review(r) for r in reviews]


# Mutation type
@strawberry.type
class Mutation:
    @strawberry.mutation
    def create_seller(self, info: Info, input: CreateSellerInput) -> Seller:
        db: Session = info.context["db"]
        seller = SellerModel(
            name=input.name,
            email=input.email,
            rating=input.rating,
            description=input.description,
        )
        db.add(seller)
        db.commit()
        db.refresh(seller)
        return convert_seller(seller)

    @strawberry.mutation
    def create_category(self, info: Info, input: CreateCategoryInput) -> Category:
        db: Session = info.context["db"]
        category = CategoryModel(
            name=input.name,
            description=input.description,
            parent_id=input.parent_id,
        )
        db.add(category)
        db.commit()
        db.refresh(category)
        return convert_category(category)

    @strawberry.mutation
    def create_product(self, info: Info, input: CreateProductInput) -> Product:
        db: Session = info.context["db"]
        product = ProductModel(
            name=input.name,
            description=input.description,
            price=input.price,
            stock=input.stock,
            seller_id=input.seller_id,
        )

        if input.category_ids:
            categories = (
                db.query(CategoryModel)
                .filter(CategoryModel.id.in_(input.category_ids))
                .all()
            )
            product.categories = categories

        db.add(product)
        db.commit()
        db.refresh(product)

        # Reload with all relationships
        product = get_products_query(db).filter(ProductModel.id == product.id).first()
        return convert_product(product)

    @strawberry.mutation
    def update_product(
        self, info: Info, id: int, input: UpdateProductInput
    ) -> Optional[Product]:
        db: Session = info.context["db"]
        product = db.query(ProductModel).filter(ProductModel.id == id).first()
        if not product:
            return None

        if input.name is not None:
            product.name = input.name
        if input.description is not None:
            product.description = input.description
        if input.price is not None:
            product.price = input.price
        if input.stock is not None:
            product.stock = input.stock

        db.commit()

        product = get_products_query(db).filter(ProductModel.id == id).first()
        return convert_product(product)

    @strawberry.mutation
    def delete_product(self, info: Info, id: int) -> bool:
        db: Session = info.context["db"]
        product = db.query(ProductModel).filter(ProductModel.id == id).first()
        if not product:
            return False
        db.delete(product)
        db.commit()
        return True

    @strawberry.mutation
    def create_review(self, info: Info, input: CreateReviewInput) -> Review:
        db: Session = info.context["db"]
        review = ReviewModel(
            product_id=input.product_id,
            reviewer_name=input.reviewer_name,
            rating=input.rating,
            title=input.title,
            comment=input.comment,
        )
        db.add(review)
        db.commit()
        db.refresh(review)
        return convert_review(review)

    @strawberry.mutation
    def create_image(self, info: Info, input: CreateImageInput) -> Image:
        db: Session = info.context["db"]
        image = ImageModel(
            product_id=input.product_id,
            url=input.url,
            alt_text=input.alt_text,
            is_primary=int(input.is_primary),
        )
        db.add(image)
        db.commit()
        db.refresh(image)
        return convert_image(image)

    @strawberry.mutation
    def add_product_to_category(
        self, info: Info, product_id: int, category_id: int
    ) -> Optional[Product]:
        db: Session = info.context["db"]
        product = db.query(ProductModel).filter(ProductModel.id == product_id).first()
        category = (
            db.query(CategoryModel).filter(CategoryModel.id == category_id).first()
        )
        if not product or not category:
            return None

        if category not in product.categories:
            product.categories.append(category)
            db.commit()

        product = get_products_query(db).filter(ProductModel.id == product_id).first()
        return convert_product(product)


# Create the schema
schema = strawberry.Schema(query=Query, mutation=Mutation)


# Custom ASGI app to inject db session into context
class GraphQLApp(GraphQL):
    async def get_context(self, request, response=None):
        db = SessionLocal()
        return {"request": request, "response": response, "db": db}


